import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { useFinance } from '../store/FinanceContext';

// Lazy load modal
const BulkAuditModal = lazy(() => import('./BulkAuditModal'));

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, isCloudSyncing, setActiveMemberIds, resetBoarding, simulateSync, approveTransaction, rejectTransaction, handleFamilyRequest } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);
  const [showBulkAudit, setShowBulkAudit] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];

  // Get permissions for the currently active view
  const activePermissions = React.useMemo(() => {
    if (activeMemberIds.length === 0 || activeMemberIds.includes('all')) return null; // Owner or Consolidated has full access
    if (activeMemberIds.length === 1) {
      return familyMembers.find(m => m.id === activeMemberIds[0])?.permissions || null;
    }
    return null;
  }, [activeMemberIds, familyMembers]);

  useEffect(() => {
    const handleScroll = () => { if (mainRef.current) setIsShrunk(mainRef.current.scrollTop > 30); };
    const currentMain = mainRef.current;
    if (currentMain) currentMain.addEventListener('scroll', handleScroll);
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  const rawNavItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊', perm: 'viewDashboard' },
    { id: 'accounts', label: 'Accounts', icon: '🏦', perm: 'viewAccounts' },
    { id: 'transactions', label: 'Transactions', icon: '💸', perm: 'viewTransactions' },
    { id: 'budget', label: 'Budget', icon: '🎯', perm: 'viewBudget' },
    { id: 'calendar', label: 'Calendar', icon: '📅', perm: 'viewCalendar' },
    { id: 'statements', label: 'Reports', icon: '📜', perm: 'viewStatements' },
    { id: 'profile', label: 'Profile', icon: '👤', perm: null },
  ];

  const navItems = rawNavItems.filter(item => {
    if (!activePermissions || !item.perm) return true;
    return (activePermissions as any)[item.perm];
  });

  const isAllSelected = activeMemberIds.includes('all');
  const isMeSelected = activeMemberIds.length === 0;

  const getSelectionLabel = () => {
    if (isAllSelected) return 'Entire Family';
    if (isMeSelected) return state.profile.name || 'Me'; 
    const member = familyMembers.find(m => m.id === activeMemberIds[0]);
    return member ? member.name : 'Group View';
  };

  const pendingApprovals = state.notifications.filter(n => n.type === 'approval_request' || n.type === 'family_request');

  const handleSignOut = async () => {
    await resetBoarding();
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col bg-slate-50 font-sans selection:bg-brand-yellow/30 overflow-hidden relative">

      {/* Header */}
      <header className={`sticky top-0 bg-slate-50/90 backdrop-blur-xl border-b border-slate-200 px-4 md:px-12 z-40 flex justify-between items-center transition-all shrink-0 ${isShrunk ? 'h-14' : 'h-16 md:h-20'}`}>
        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-[#03246B] rounded-lg flex items-center justify-center font-bold text-white text-xs">M</div>
              <h1 className="text-lg font-black text-[#03246B] tracking-tight hidden sm:block uppercase tracking-widest">MyFin</h1>
           </div>
        </div>

        <div className="flex items-center gap-3">
          <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 bg-white rounded-2xl text-[#03246B] flex items-center justify-center border border-slate-200 transition-all hover:bg-slate-50">
             <span className="text-xl">🔔</span>
             {pendingApprovals.length > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-white"></span>}
          </button>

          <button onClick={() => setActiveTab('rankings')} className={`relative w-10 h-10 rounded-2xl flex items-center justify-center border transition-all ${activeTab === 'rankings' ? 'bg-[#03246B] text-white border-[#03246B]' : 'bg-white text-[#03246B] border-slate-200 hover:bg-slate-50'}`}>
             <span className="text-xl">🏆</span>
          </button>

          <div className="relative">
            <button onClick={() => setShowMemberSelector(!showMemberSelector)} className="relative flex items-center justify-start px-4 py-2.5 bg-white rounded-2xl text-[9px] font-black uppercase tracking-widest border border-slate-200 text-[#03246B] shadow-sm pr-7">
              <span className="max-w-[100px] truncate">{getSelectionLabel()}</span>
              <span className="text-xs absolute top-0.5 right-1">👥</span>
            </button>
            {showMemberSelector && (
              <div className="absolute top-full right-0 mt-3 w-64 bg-white border border-slate-200 rounded-[2rem] shadow-2xl z-50 p-3 space-y-1">
                  <button onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isMeSelected ? 'bg-[#03246B] text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>👤 My Vault</button>
                  <button onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isAllSelected ? 'bg-[#03246B] text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>🌍 Consolidated</button>
                  <div className="h-px bg-slate-100 my-2"></div>
                  {familyMembers.map(m => (
                    <button key={m.id} onClick={() => { setActiveMemberIds([m.id]); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeMemberIds.includes(m.id) ? 'bg-[#03246B] text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>
                      {m.name} {m.status === 'pending_invitation' && '⏳'}
                    </button>
                  ))}
                  <div className="h-px bg-slate-100 my-2"></div>
                  <button onClick={() => { handleSignOut(); setShowMemberSelector(false); }} className="w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest text-rose-500 hover:bg-rose-50 flex items-center gap-2">
                     <span>🚪</span> Sign Out
                  </button>
              </div>
            )}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main ref={mainRef} className="flex-1 overflow-y-auto custom-scrollbar pb-32 md:pb-28">
        <div className="max-w-7xl mx-auto p-4 md:p-8 lg:p-12">
          {children}
        </div>

        {showNotifications && pendingApprovals.length > 0 && (
          <div className="fixed top-20 right-4 md:right-16 w-80 bg-white border border-slate-200 rounded-[2.5rem] shadow-2xl z-50 p-6 animate-in slide-in-from-right-10 flex flex-col max-h-[70vh]">
            <div className="flex justify-between items-center mb-6">
               <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Action Required</h4>
               {pendingApprovals.filter(n => n.type === 'approval_request').length > 1 && (
                 <button 
                   onClick={() => { setShowBulkAudit(true); setShowNotifications(false); }}
                   className="text-[9px] font-black text-[#03246B] uppercase tracking-widest bg-indigo-50 px-2 py-1 rounded-lg"
                 >
                   Bulk Audit
                 </button>
               )}
            </div>

            <div className="space-y-4 overflow-y-auto custom-scrollbar flex-1 pr-1">
               {pendingApprovals.map(n => {
                 const isFamilyRequest = n.type === 'family_request';
                 return (
                   <div key={n.id} className={`p-4 rounded-2xl border ${isFamilyRequest ? 'bg-indigo-50 border-indigo-200 shadow-sm' : 'bg-slate-50 border-slate-100'}`}>
                      {isFamilyRequest && <span className="inline-block bg-[#03246B] text-white text-[7px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest mb-2">Priority Request</span>}
                      <p className="text-[10px] font-black text-slate-800 uppercase leading-tight">{n.title}</p>
                      <p className="text-[9px] text-slate-500 font-medium mt-1">{n.message}</p>
                      <div className="flex gap-2 mt-4">
                         {isFamilyRequest ? (
                           <>
                              <button onClick={() => handleFamilyRequest(n.id, true)} className="flex-1 py-2 bg-[#03246B] text-white text-[8px] font-black uppercase rounded-lg shadow-lg shadow-indigo-200">Verify & Link</button>
                              <button onClick={() => handleFamilyRequest(n.id, false)} className="flex-1 py-2 bg-white text-slate-400 border border-slate-200 text-[8px] font-black uppercase rounded-lg">Ignore</button>
                           </>
                         ) : (
                           <>
                              <button onClick={() => approveTransaction(n.transactionId!)} className="flex-1 py-2 bg-emerald-600 text-white text-[8px] font-black uppercase rounded-lg">Approve</button>
                              <button onClick={() => rejectTransaction(n.transactionId!)} className="flex-1 py-2 bg-rose-50 text-rose-500 text-[8px] font-black uppercase rounded-lg">Reject</button>
                           </>
                         )}
                      </div>
                   </div>
                 );
               })}
            </div>
          </div>
        )}

        {showBulkAudit && (
          <Suspense fallback={<div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md"><div className="w-10 h-10 border-4 border-white/20 border-t-white rounded-full animate-spin"></div></div>}>
            <BulkAuditModal onClose={() => setShowBulkAudit(false)} />
          </Suspense>
        )}
      </main>

      {/* Unified Bottom Dock Navigation */}
      <div className="fixed bottom-0 left-0 right-0 z-[60] p-4 md:p-6 pointer-events-none">
        <nav className="max-w-4xl mx-auto bg-white/95 backdrop-blur-xl border border-slate-200 rounded-[2.5rem] px-4 md:px-8 py-2 flex justify-between items-center shadow-[0_15px_40px_-10px_rgba(0,0,0,0.2)] pointer-events-auto">
            {navItems.map(item => (
              <button 
                key={item.id} 
                onClick={() => setActiveTab(item.id)}
                className={`flex flex-col items-center justify-center min-w-[50px] md:min-w-[90px] h-14 rounded-2xl transition-all active:scale-90 group relative ${activeTab === item.id ? 'text-[#03246B]' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <span className={`text-xl md:text-2xl mb-1 transition-all ${activeTab === item.id ? 'scale-110 -translate-y-0.5' : 'group-hover:-translate-y-0.5'}`}>
                  {item.icon}
                </span>
                <span className={`text-[8px] md:text-[9px] font-black uppercase tracking-widest hidden sm:block ${activeTab === item.id ? 'opacity-100' : 'opacity-40 group-hover:opacity-100'}`}>
                  {item.label}
                </span>
                {activeTab === item.id && (
                  <span className="absolute -bottom-1.5 w-1.5 h-1.5 rounded-full bg-[#03246B] animate-in zoom-in"></span>
                )}
              </button>
            ))}
        </nav>
      </div>

    </div>
  );
};

